import{_ as a,o as i,c as t,ag as o}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Integration e-mail","description":"","frontmatter":{},"headers":[],"relativePath":"fr/settings/email.md","filePath":"fr/settings/email.md"}'),r={name:"fr/settings/email.md"};function l(s,e,n,d,u,m){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="integration-e-mail" tabindex="-1">Integration e-mail <a class="header-anchor" href="#integration-e-mail" aria-label="Permalink to &quot;Integration e-mail&quot;">​</a></h1><p>Configurez la maniere dont MyCompanyDesk envoie des e-mails a vos clients -- de la livraison des factures aux rappels de paiement.</p><h2 id="methodes-d-envoi-d-e-mails" tabindex="-1">Methodes d&#39;envoi d&#39;e-mails <a class="header-anchor" href="#methodes-d-envoi-d-e-mails" aria-label="Permalink to &quot;Methodes d&#39;envoi d&#39;e-mails&quot;">​</a></h2><p>MyCompanyDesk prend en charge trois manieres d&#39;envoyer des e-mails :</p><h3 id="_1-e-mail-integre-par-defaut" tabindex="-1">1. E-mail integre (par defaut) <a class="header-anchor" href="#_1-e-mail-integre-par-defaut" aria-label="Permalink to &quot;1. E-mail integre (par defaut)&quot;">​</a></h3><p>Par defaut, les e-mails sont envoyes via le service de messagerie de MyCompanyDesk. Aucune configuration necessaire.</p><h3 id="_2-integration-gmail" tabindex="-1">2. Integration Gmail <a class="header-anchor" href="#_2-integration-gmail" aria-label="Permalink to &quot;2. Integration Gmail&quot;">​</a></h3><p>Envoyez des e-mails directement depuis votre compte Gmail :</p><ol><li>Allez dans <strong>Parametres &gt; Communication &gt; E-mail</strong></li><li>Cliquez sur <strong>Connecter Gmail</strong></li><li>Autorisez MyCompanyDesk a envoyer en votre nom via Google OAuth</li><li>Les e-mails apparaissent desormais comme envoyes depuis votre adresse Gmail</li></ol><p><strong>Avantages :</strong></p><ul><li>Les e-mails affichent votre adresse Gmail comme expediteur</li><li>Les e-mails envoyes apparaissent dans votre dossier Gmail Envoyes</li><li>Meilleure delivrabilite (reputation de votre propre domaine)</li></ul><h3 id="_3-integration-outlook-microsoft" tabindex="-1">3. Integration Outlook / Microsoft <a class="header-anchor" href="#_3-integration-outlook-microsoft" aria-label="Permalink to &quot;3. Integration Outlook / Microsoft&quot;">​</a></h3><p>Envoyez depuis votre compte Outlook ou Microsoft 365 :</p><ol><li>Allez dans <strong>Parametres &gt; Communication &gt; E-mail</strong></li><li>Cliquez sur <strong>Connecter Outlook</strong></li><li>Autorisez via Microsoft OAuth</li><li>Les e-mails sont envoyes depuis votre adresse Outlook</li></ol><h3 id="_4-smtp-personnalise" tabindex="-1">4. SMTP personnalise <a class="header-anchor" href="#_4-smtp-personnalise" aria-label="Permalink to &quot;4. SMTP personnalise&quot;">​</a></h3><p>Pour un controle total, utilisez votre propre serveur SMTP :</p><ol><li>Allez dans <strong>Parametres &gt; Communication &gt; E-mail</strong></li><li>Entrez vos details SMTP : <ul><li><strong>Host</strong> -- Adresse du serveur SMTP</li><li><strong>Port</strong> -- Port du serveur (587 pour TLS, 465 pour SSL)</li><li><strong>Username</strong> -- Identifiant SMTP</li><li><strong>Password</strong> -- Mot de passe SMTP</li></ul></li><li>Cliquez sur <strong>Tester la connexion</strong> pour verifier le fonctionnement</li><li>Enregistrez</li></ol><h2 id="modeles-d-e-mail" tabindex="-1">Modeles d&#39;e-mail <a class="header-anchor" href="#modeles-d-e-mail" aria-label="Permalink to &quot;Modeles d&#39;e-mail&quot;">​</a></h2><p>Personnalisez les e-mails envoyes avec vos factures et rappels.</p><h3 id="modele-d-e-mail-de-facture" tabindex="-1">Modele d&#39;e-mail de facture <a class="header-anchor" href="#modele-d-e-mail-de-facture" aria-label="Permalink to &quot;Modele d&#39;e-mail de facture&quot;">​</a></h3><p>L&#39;e-mail par defaut envoye lors de la livraison d&#39;une facture. Personnalisez :</p><ul><li><strong>Objet</strong> -- L&#39;objet de l&#39;e-mail (prend en charge les variables comme le numero de facture)</li><li><strong>Corps</strong> -- Le contenu du message</li><li><strong>Langue</strong> -- Definissez des modeles par langue</li></ul><h3 id="modele-d-e-mail-de-rappel" tabindex="-1">Modele d&#39;e-mail de rappel <a class="header-anchor" href="#modele-d-e-mail-de-rappel" aria-label="Permalink to &quot;Modele d&#39;e-mail de rappel&quot;">​</a></h3><p>L&#39;e-mail envoye lors du suivi des factures en retard. Personnalisez les memes champs que ci-dessus mais avec un ton plus urgent.</p><h3 id="apercu" tabindex="-1">Apercu <a class="header-anchor" href="#apercu" aria-label="Permalink to &quot;Apercu&quot;">​</a></h3><p>Avant l&#39;envoi, vous pouvez previsualiser n&#39;importe quel e-mail pour voir exactement ce que votre client recevra :</p><ul><li>Rendu HTML avec votre image de marque</li><li>Apercu de la piece jointe PDF</li><li>Inclusion du lien de paiement</li></ul><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h2><p>Les modeles d&#39;e-mail prennent en charge les variables dynamiques :</p><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>{invoice_number}</code></td><td>Le numero de facture</td></tr><tr><td><code>{customer_name}</code></td><td>Le nom du client</td></tr><tr><td><code>{amount}</code></td><td>Le montant total de la facture</td></tr><tr><td><code>{due_date}</code></td><td>La date d&#39;echeance du paiement</td></tr><tr><td><code>{company_name}</code></td><td>Le nom de votre entreprise</td></tr><tr><td><code>{payment_link}</code></td><td>Le lien vers le paiement en ligne</td></tr></tbody></table><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><p>Configurez les notifications par e-mail que vous recevez :</p><ul><li><strong>Facture payee</strong> -- Recevez une notification lorsqu&#39;un client paie</li><li><strong>Demande de devis recue</strong> -- Alerte pour les nouvelles demandes de devis</li><li><strong>Activite de l&#39;equipe</strong> -- Mises a jour sur les actions des membres de l&#39;equipe</li></ul><p>Les preferences de notification peuvent etre definies dans votre <a href="/fr/account/profile">Profil</a>.</p><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Connectez Gmail ou Outlook pour la meilleure delivrabilite</li><li>Testez toujours votre modele d&#39;e-mail avant d&#39;envoyer votre premiere facture</li><li>Configurez des modeles specifiques par langue si vous servez des clients dans plusieurs langues</li><li>Utilisez le modele de rappel pour des relances professionnelles sur les factures en retard</li></ul>',36)])])}const h=a(r,[["render",l]]);export{p as __pageData,h as default};
